import React, { useState } from "react";
import "./UploadCV.css";

const UploadCV = ({ onResult, onLoading }) => {
  const [file, setFile] = useState(null);
  const [text, setText] = useState("");
  const [mode, setMode] = useState("file"); // "file" | "text"
  const [dragging, setDragging] = useState(false);
  const [error, setError] = useState("");

  const handleFileChange = (e) => {
    const selected = e.target.files[0];
    if (selected && selected.type === "application/pdf") {
      setFile(selected);
      setError("");
    } else {
      setError("Chỉ chấp nhận file PDF.");
      setFile(null);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setDragging(false);
    const dropped = e.dataTransfer.files[0];
    if (dropped && dropped.type === "application/pdf") {
      setFile(dropped);
      setError("");
    } else {
      setError("Chỉ chấp nhận file PDF.");
    }
  };

  const handleSubmit = async () => {
    setError("");
    onLoading(true);
    onResult(null);

    try {
      let response;
      if (mode === "file") {
        if (!file) { setError("Vui lòng chọn file PDF."); onLoading(false); return; }
        const formData = new FormData();
        formData.append("file", file);
        response = await fetch("http://localhost:8000/predict/file", {
          method: "POST",
          body: formData,
        });
      } else {
        if (!text.trim()) { setError("Vui lòng nhập nội dung CV."); onLoading(false); return; }
        response = await fetch("http://localhost:8000/predict/text", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ text }),
        });
      }

      const data = await response.json();
      if (!response.ok) throw new Error(data.detail || "Lỗi từ server.");
      if (!data.success) throw new Error(data.error || "Không thể phân tích CV.");
      onResult(data.data);
    } catch (err) {
      setError(err.message);
    } finally {
      onLoading(false);
    }
  };

  return (
    <div className="upload-card">
      {/* Mode Toggle */}
      <div className="mode-toggle">
        <button
          className={`toggle-btn ${mode === "file" ? "active" : ""}`}
          onClick={() => setMode("file")}
        >
          📄 Upload PDF
        </button>
        <button
          className={`toggle-btn ${mode === "text" ? "active" : ""}`}
          onClick={() => setMode("text")}
        >
          ✏️ Nhập Text
        </button>
      </div>

      {/* File Upload Mode */}
      {mode === "file" && (
        <div
          className={`dropzone ${dragging ? "dragging" : ""} ${file ? "has-file" : ""}`}
          onDragOver={(e) => { e.preventDefault(); setDragging(true); }}
          onDragLeave={() => setDragging(false)}
          onDrop={handleDrop}
          onClick={() => document.getElementById("cv-file-input").click()}
        >
          <input
            id="cv-file-input"
            type="file"
            accept=".pdf"
            style={{ display: "none" }}
            onChange={handleFileChange}
          />
          {file ? (
            <div className="file-info">
              <span className="file-icon">📋</span>
              <span className="file-name">{file.name}</span>
              <span className="file-size">({(file.size / 1024).toFixed(1)} KB)</span>
            </div>
          ) : (
            <div className="dropzone-hint">
              <span className="upload-icon">☁️</span>
              <p>Kéo thả file PDF vào đây</p>
              <p className="sub-hint">hoặc <span className="link">click để chọn file</span></p>
            </div>
          )}
        </div>
      )}

      {/* Text Mode */}
      {mode === "text" && (
        <textarea
          className="text-input"
          placeholder="Dán nội dung CV vào đây (tiếng Anh hoặc tiếng Việt)..."
          value={text}
          onChange={(e) => setText(e.target.value)}
          rows={8}
        />
      )}

      {error && <div className="error-msg">⚠️ {error}</div>}

      <button className="submit-btn" onClick={handleSubmit}>
        🔍 Phân tích CV
      </button>
    </div>
  );
};

export default UploadCV;
